import { fixBrushDirection } from './tools/selection-to-domain';
import { CHART_DOMAIN_HELPERS } from '../../../brush/chart-helpers/domain-helpers';
import { splat } from '../../../utils/zcutils';
import { UNDEFINED } from '../../../core/zc-constants';

/**
 *
 * @param instanceMap
 * @param selection
 * @param type
 */
export function ChartBrushDataFinder(instanceMap, type, selection, forced) {
    let eventManager = this,
        chart = eventManager.chart,
        brushInstance = instanceMap.instance,
        brushTypeOriginal = brushInstance.options.type,
        brushType = fixBrushDirection(brushTypeOriginal, chart.axes.rotated),
        brushedAxes = plotBrushed(selection, brushType, UNDEFINED, forced);

    // updated every time
    brushInstance.brushedAxes = brushedAxes;

    return CHART_DOMAIN_HELPERS.GET_DOMAIN_INFO(selection, brushedAxes, brushTypeOriginal, chart);
}

/**
 *
 * @param selection
 * @param type
 * @param mindist
 * @return {string[]}
 */
function plotBrushed(selection, type, mindist = 0, forced = false) {
    let brushedAxes = {};
    if (!selection) {
        if (forced) {
            if (type === 'xy') {
                brushedAxes.x = brushedAxes.y = true;
            } else {
                brushedAxes[type] = true;
            }
        }
    } else {
        selection = splat(selection);
        if (type === 'xy') {
            let [x, x1] = selection;
            brushedAxes = {
                x: x1[0] - x[0] > mindist,
                y: x1[1] - x[1] > mindist
            };
        } else {
            if (selection[1] - selection[0] > mindist) {
                brushedAxes[type] = true;
            }
        }
    }
    return Object.keys(brushedAxes).filter(axes => brushedAxes[axes]);
}
